using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool implementations ---

/// <summary>Stores notes the agent collects during research.</summary>
static class Notebook
{
    private static readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record key facts, quotes, or insights discovered during research.")]
    public static string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public static string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

/// <summary>Provides web search capability using Bing.</summary>
static class WebSearch
{
    private static readonly HttpClient Http = new();

    [Description("Search the web for information on a query. Returns a list of relevant result titles and snippets.")]
    public static async Task<string> Search(
        [Description("The search query")] string query)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var html = await Http.GetStringAsync(
                $"https://html.duckduckgo.com/html/?q={encoded}");

            var results = ParseResults(html);
            if (results.Count == 0)
                return "No results found.";

            return string.Join("\n---\n", results.Take(5));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<string> ParseResults(string html)
    {
        var results = new List<string>();
        var span = html.AsSpan();
        const string titleMarker = "class=\"result__a\"";
        const string snippetMarker = "class=\"result__snippet\"";

        int pos = 0;
        while (pos < span.Length && results.Count < 5)
        {
            int titleIdx = html.IndexOf(titleMarker, pos, StringComparison.Ordinal);
            if (titleIdx < 0) break;

            string title = ExtractTagContent(html, titleIdx);
            int snippetIdx = html.IndexOf(snippetMarker, titleIdx, StringComparison.Ordinal);
            string snippet = snippetIdx >= 0 ? ExtractTagContent(html, snippetIdx) : "";

            if (!string.IsNullOrWhiteSpace(title))
                results.Add($"Title: {StripTags(title).Trim()}\nSnippet: {StripTags(snippet).Trim()}");

            pos = snippetIdx >= 0 ? snippetIdx + 1 : titleIdx + 1;
        }
        return results;
    }

    private static string ExtractTagContent(string html, int attrPos)
    {
        int gt = html.IndexOf('>', attrPos);
        if (gt < 0) return "";
        int closeTag = html.IndexOf('<', gt + 1);
        if (closeTag < 0) return "";
        // Grab content including nested tags up to the closing tag
        int depth = 1;
        int i = gt + 1;
        while (i < html.Length && depth > 0)
        {
            if (html[i] == '<')
            {
                if (i + 1 < html.Length && html[i + 1] == '/')
                    depth--;
                else
                    depth++;
            }
            i++;
        }
        return html[(gt + 1)..Math.Min(i - 1, html.Length)];
    }

    private static string StripTags(string html)
    {
        var result = new System.Text.StringBuilder();
        bool inTag = false;
        foreach (char c in html)
        {
            if (c == '<') inTag = true;
            else if (c == '>') inTag = false;
            else if (!inTag) result.Append(c);
        }
        return WebUtility.HtmlDecode(result.ToString());
    }
}

// --- Main program ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrEmpty(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable.");
    return 1;
}

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearch.Search),
    AIFunctionFactory.Create(Notebook.SaveNote),
    AIFunctionFactory.Create(Notebook.GetNotes),
};

Console.WriteLine("🔬 Research Agent");
Console.WriteLine("=================");
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}\n");

var systemPrompt = """
    You are a thorough research agent. Your goal is to research the given topic 
    using web searches and compile a well-organized summary.

    Follow this process:
    1. Search the web for the topic using multiple varied queries (at least 2-3 searches).
    2. Save important facts, statistics, and insights as notes using the SaveNote tool.
    3. After gathering enough information, retrieve your notes with GetNotes.
    4. Produce a final research summary with sections: Overview, Key Findings, and Conclusion.

    Be thorough but concise. Cite the sources where possible.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Research the following topic: {topic}"),
};

var options = new ChatOptions { Tools = [.. tools] };

var response = await chatClient.GetResponseAsync(messages, options);

Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
Console.WriteLine(response.Text);
Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

return 0;

